namespace submit1
{
struct Dsu 
{
    vector<ll> f;
    ll n;
    Dsu(ll n1): f(2 * n1 + 1), n(n1)
    {
        iota(ALL(f), 0);
    }

    ll find(ll u) 
    {
        while (f[u] != u)
            u = f[u] = f[f[u]];
        return u;
    }

    bool merge(ll u, ll v) 
    {
        u = find(u);
        v = find(v);
        if (u == v)
        {
            return false;
        }
        if (u > v)
        {
            swap (u, v);
        }
        f[v] = u;
        if(u <= n and v <= n)
        {
            merge(u + n, v + n);
        }
        return true;
    }
};

void solve()
{
    ll n, m;
    cin >> n >> m;
    Dsu dsu(n);
    for(ll i = 0; i < m; ++i)
    {
        ll a, b;
        cin >> a >> b;
        dsu.merge(a + n, b);
    }
    DOUT(dsu.f);
    vector<ll> ans(n + 1);
    map<ll, ll> ma;
    for(ll i = 1; i <= n; ++i)
    {
        if (ma.count(dsu.find(i)))
        {
            ans[i] = ma[dsu.find(i)];
        }
        else
        {
            ans[i] = ma[dsu.find(i)] = ma.size() + 1;
        }
    }
    cout << ans;
}
}

