#include<bits/stdc++.h>
#define int long long
using namespace std;
const int mod = 998244353;
const int N = 1e6 + 5;
int n, m, a[N], sum, f[N], fac[N], inv[N], cnt[N];
int qpow(int a, int b)
{
	int res = 1, base = a;
	while(b)
	{
		if(b & 1) res = res * base % mod;
		base = base * base % mod;
		b >>= 1;
	}
	return res;
}

int C(int n, int m) {
	return ( ((fac[n] * inv[n-m]) % mod ) * inv[m] ) % mod;
}

signed main()
{
	ios::sync_with_stdio(false);
	std::cin.tie(0);

	cin >> n >> m;

	for(int i=1; i<=n; i++) 
		cin >> a[i], cnt[a[i]] ++ ;

	fac[0] = inv[0] = inv[1] = fac[1] = 1;
    for(int i=2; i<=n; i++) 
		inv[i] = (mod - mod/i) * inv[mod%i] % mod; 

	for(int i=2; i<=n; i++)
		inv[i] = inv[i-1] * inv[i] % mod, 
		fac[i] = fac[i-1] * i % mod;

	f[1] = 1;
	for(int i=2; i<=1e6; i++)
	{
		if(!cnt[i]) continue;
		for(int j=(m / i) * i; j >= i; j -= i)		// 只有是 i 的倍数才可能是 i ^ k 的倍数 
			for(int k=1, s=i; k<=cnt[i] and j % s == 0; k++, s*=i) 		// i ^ k 
				f[j] += f[j / s] * C(cnt[i], k) % mod, f[j] %= mod;
	}

	int sum = qpow(2, n);
	for(int i=1; i<=m; i++)
		sum -= (f[i] * qpow(2, cnt[1])) % mod, sum = ((sum % mod) + mod) % mod;

	cout << sum;
	return 0;
}

