    {
        iota(ALL(f), 0);
    }

    ll find(ll x)
    {
        while(x != f[x])
        {
            x = f[x] = f[f[x]];
        }
        return x;
    }

    bool merge(ll a, ll b)
    {
        a = find(a);
        b = find(b);
        if (a == b)
        {
            return false;
        }
        if (s[a] > s[b])
        {
            swap(a, b);
        }
        f[a] = b;
        s[b] += s[a];
        return true;
    }
    bool merge(pair<ll, ll> t)
    {
        ll a = t.first, b = t.second;
        a = find(a);
        b = find(b);
        if (a == b)
        {
            return false;
        }
        if (s[a] > s[b])
        {
            swap(a, b);
        }
        f[a] = b;
        s[b] += s[a];
        return true;
    }
    bool same(ll a, ll b)
