struct Dsu {
    vector<ll> f, size;
    Dsu(ll n) : f(n+1), size(n+1, 1)
    {
        iota(ALL(f), 0);
    }
    ll find(ll x)
    {
        while (x != f[x])
        {
            x = f[x] = f[f[x]];
        }
        return x;
    }
    bool merge(ll x, ll y)
    {
        x = find(x);
        y = find(y);
        if (x != y)
        {
            f[x] = y;            
            size[y] += size[x];
            return true;
        }
        return false;
    }
};

void solve()
{
    ll n, a;
    cin >> n >> a;
    vector<vector<ll>> g(n  + 1);
