    {
        ll u, v;
        cin >> u >> v;
        g[u].push_back(v);
        g[v].push_back(u);
    }
    vector<ll> father(n + 1);
    vector<ll> depth(n + 1);
    auto dfs = [&](auto&& self, ll u, ll p)->void
    {
        father[u] = p;
        depth[u] = depth[p] + 1;
        for(auto v : g[u])
        {
            if(v != p)
            {
                self(self, v, u);
            }
        }
    };
    dfs(dfs, 1, 1);
    DOUT("t");
    auto lca = [&](ll u, ll v, auto&& dsu)
    {
        u = dsu.find(u);
        v = dsu.find(v);
        while (u != v)
        {
            if (depth[u] < depth[v])
            {
                swap(u, v);
            }
            dsu.merge(u, father[u]);
            u = dsu.find(father[u]);
        }
    };
    Dsu good(n);
    for (ll i = 0 ;i < a; ++i)
    {
        ll u, v;
        cin >> u >> v;
        lca(u, v, good);
    }
    Dsu bad(n);
    ll u, v;
    cin >> u >> v;
    lca(u, v, bad);
    ll cnt = 0;
    for (ll i = 1; i <= n; ++i)
    {
        if (good.size[good.find(i)] == 1 and bad.size[bad.find(i)] > 1)
        {
            ++cnt;
        }
    }
