    ll n;
    cin >> n;
    vector<ll> r(n + 1);
    cin >> r[1];
    for (ll i = 2; i <= n; ++i)
    {
        r[i] = (r[i - 1] * 6807 + 2831) % 201701;
    }
    for (ll i = 1; i <= n; ++i)
    {
        r[i] %= 100;
    }
    vector<vector<ll>> a(n + 1, vector<ll>(100));
    for(ll i = 1; i <= n; ++i)
    {
        for (ll j = 0; j < 100; ++j)
        {
            ll t = min((j + 100 - r[i])% 100, (r[i] - j + 100)%100);
            a[i][j] = t * t;
        }
    }
    vector<vector<ll>> dp(n + 1, vector<ll>(100, INT_MAX));
    for (ll i = 0; i < 100; ++i)
    {
        dp[1][i] = a[1][i];
    }
    for (ll i = 2; i <= n; ++i)
    {
        for (ll j = i - 1; j < 100; ++j)
        {
            for (ll k = i - 2; k < j; ++k)
            {
                chmin(dp[i][j], dp[i - 1][k] + a[i][j]);
            }
        }
    }
    ll ans = INT_MAX;
    for(ll i = n - 1; i < 100; ++i)
    {
        chmin(ans, dp[n][i]);
    }
    cout << ans;
}
