int64_t get_number(const string& s, bool& found)
{
	char* p = const_cast<char*>(s.c_str());
	int64_t r = 0;
	found = false;
	while (*p != '\0') {
		auto q = p;
		if (*p == '-' or isdigit(*p)) {
			r += strtoll(p, &q, 10);
			if (q > p) {
				found = true;
			}
		}

		if (q != p) {
			p = q;
		}
		else {
			++ p;
		}
	}
	return r;
}

