void FixLine(string& a)
{
    int w=0;
    for(size_t l=0;l < a.size();++l)
    {
        if(a[l]=='<')
        {
            w--;
            if(w==-1)
            {
                w=0;
            }
            continue;
        }
        a[w]=a[l];
        w++;
    }
    a.resize(w);
}

vector<string> GetLine()
{
    vector<string> a;

    while(true)
    {
        string t;
        getline(cin,t);
        if(t=="EOF")
        {
            break;
        }
        else
        {
            FixLine(t);
            a.push_back(t);

        }
    }
    return a;
}


