        g[u].push_back(v);
        g[v].push_back(u);
    }
    vector<vector<ll>> jumper(n + 1, vector<ll>(25));
    vector<ll> depth(n + 1);
    auto dfs = [&](auto&& self, ll u, ll p)->void
    {
        jumper[u][0] = p;
        depth[u] = depth[p] + 1;
        for(auto v : g[u])
        {
            if(v != p)
            {
                self(self, v, u);
            }
        }
    };
    dfs(dfs, s, s);
