struct Dsu
{
    vector<ll> f, s;
    Dsu(ll n):f(n + 1), s(n + 1, 1)
    {
        iota(ALL(f), 0);
    }
    ll find(ll x)
    {
        while(x != f[x])
        {
            x = f[x] = f[f[x]];
        }
        return x;
    }
    bool merge(ll a, ll b)
    {
        a = find(a);
        b = find(b);
        if (a > b)
        {
            swap(a, b);
        }
        if (a == b)
        {
            return false;
        }
        f[a] = b;
        s[b] += s[a];
        return true;
    }
};
