    {
        iota(ALL(f), 0);
    }
    ll find(ll x)
    {
        while(x != f[x])
        {
            x = f[x] = f[f[x]];

        }
        return x;
    }
    bool merge(ll x, ll y)
    {
        x = find(x);
        y = find(y);
        if(x == y)
        {
            return false;
        }
        if (s[x] < s[y])
        {
            swap(x, y);
        }
        f[y] = x;
        return true;
    }
};
struct Edge
{
    ll u, v, w;
};
auto kruskal = [](auto& edge, ll n, auto f)
{
    sort(ALL(edge), [](auto x, auto y){return x.w<y.w;});
    auto dsu = Dsu(n);
    ll cnt = 0;
    for(auto i: edge)
    {
        if (dsu.merge(i.u, i.v))
        {
            f(i);
            if(++cnt == n - 1)
            {
                break;
            }
        }
    }
    return cnt == n - 1;
};
