namespace submit1
{
struct Dsu
{
    vector<ll> f, s;
    ll cnt;
    Dsu(ll n):f(n + 1), s(n + 1, 1), cnt(n)
    {
        iota(ALL(f), 0);
    }
    ll find(ll x)
    {
        while(x != f[x])
        {
            x = f[x] = f[f[x]];
        }
        return x;
    }
    bool merge(ll x, ll y)
    {
        x = find(x);
        y = find(y);
        if(x == y)
        {
            return false;
        }
        if (s[x] < s[y])
        {
            swap(x, y);
        }
        f[y] = x;
        s[y] += s[x];
        --cnt;
        return true;
    }
};
struct Edge
{
    ll u, v;
    double w;
};

double dis(ll x, ll y, ll x1, ll y1)
{
    return sqrt(pow(x - x1, 2) + pow(y - y1, 2));
}
void solve()
{
    ll n, m;
    cin >> n >> m;
    vector<pair<ll, ll>> a(n + 1);
    for(ll i = 1; i <= n; ++i)
    {
        cin >> a[i].first >> a[i ].second;
    }
    auto dsu = Dsu(n);
    for(ll i = 0; i < m; ++i)
    {
        ll u, v;
        cin >> u >> v;
        dsu.merge(u, v);
    }
    vector<Edge> edge;
    for (ll i = 1; i <= n; ++i)
    {
        for (ll j = i + 1; j <= n; ++j)
        {
            edge.push_back({i, j, dis(a[i].first, a[i].second, a[j].first, a[j].second)});
        }
    }
    auto kruskal = [&]()
    {
        sort(ALL(edge), [](auto x, auto y){return x.w < y.w;});
        double ans = 0;
        for (auto i : edge)
        {
            if (dsu.merge(i.u, i.v))
            {
                ans += i.w;
                if (dsu.cnt == 1)
                {
                    break;
                }
            }
        }
        return ans;
    };
    printf("%.2lf",kruskal());
}
}

