struct Dsu {
    vector<int> f, s;
    Dsu(int n): f(n+1), s(n+1, 1) {
        iota(ALL(f), 0);
    }

    int find(int x) {
        while (x != f[x]) x = f[x] = f[f[x]];
        return x;
    }

    bool merge(int x, int y) {
        x = find(x); y = find(y);
        if (x == y) return false;
        if (s[x] < s[y]) swap(x, y);
        f[y] = x;
        s[x] += s[y];
        return true;
    }
};

struct Edge {
    ll u, v, w;
};

auto kruskal = [](auto& edges, ll n, auto f) {
    sort(ALL(edges), [](auto const& a, auto const& b) { return a.w < b.w; });
    auto dsu = Dsu(n);
    ll cnt = 0;
    for (auto& e : edges) {
        if (dsu.merge(e.u, e.v)) {
            f(e);
            if (++cnt == n - 1) break;
        }
    }
    return cnt == n-1;
};

