bool cmin(ll& x, ll y)
{
    return (x > y)? (x = y, true):false;
}
void Main()
{
    ll n, m, s, t;
    cin >> n >> m >> s >> t;
    vector<vector<pii>> g(n + 1);
    for(ll i = 0;i < m; ++i)
    {
        ll u, v, w;
        cin>> u >> v >> w;
        g[u].push_back({v, w});
        g[v].push_back({u, w});
    }
    auto dijkstra = [](vector<vector<pii>> g, ll s)
    {
        priority_queue<pii, vector<pii>, greater<>> q;
        q.push({0, s});
        vector<ll> dis(g.size(), 1e18);
        dis[s] = 0;
        while(not q.empty())
        {
            auto t = q.top();
            q.pop();
            ll u = t.second;
            if (t.first > dis[u])
            {
                continue;
            }
            for (auto i : g[u])
            {
                ll v = i.first;
                ll w = i.second;
                if (cmin(dis[v], dis[u] + w))
                {
                    q.push({dis[v], v});
                }
            }
        }
        return dis;
    };
    cout << dijkstra(g, s)[t];
}
}

