            {
                if (jumper[x][i] != jumper[ans][i])
                {
                    x = jumper[x][i];
                    ans = jumper[ans][i];
                }
            }
            if (x != ans)
            {
                ans = jumper[ans][0];
            }
        }
        DOUT(ans);
        cout << ma[ans] << '\n';
    }
}
