template <class T>
T power(T b, ll e)
{
    T r = 1;
    while(e)
    {
        if (e % 2 == 1)
        {
            r = r * b;
        }
        e >>= 1;
        b = b * b;
    }
    return r;
}
ll MOD = 1e9+7;

struct Mint
{
    ll v;
    Mint(ll a)
    {
        while(a < 0)
            a += MOD;
        v = a % MOD;
    }
    Mint()
    {
        v = 0;
    }
    Mint inv() const
    {
        return power(*this, MOD - 2);
    }
    Mint operator*(Mint b) const
    {
        return v * b.v;
    }
    Mint operator+(Mint b) const
    {
        return v + b.v;
    }
    Mint operator-(Mint b) const
    {
        return v - b.v;
    }
    Mint operator/(Mint b) const
    {
        return v * b.inv().v;
    }

};
struct Comb
{
    vector<Mint> fac, ifac, inv;
    Comb(ll n): fac(n + 1), ifac(n + 1), inv(n + 1)
    {
        fac[0] = 1;
        for (ll i = 1; i <= n; ++i)
        {
            fac[i] = fac[i - 1] * i;
        }
        ifac[n] = fac[n].inv();
        for (auto i = n; i >= 1; --i)
        {
            ifac[i - 1] = ifac[i] * i;
            inv[i] = fac[i - 1] * ifac[i];
        }
    }
    Mint a(ll n, ll m) const
    {
        if (n < m or m < 0)
        {
            return 0;
        }
        return fac[n] * ifac[n - m];
    }
    Mint c(ll n, ll m)
    {
        return a(n , m) * ifac[m];
    }
};
void solve()
{
    Comb comb(1050);
    for (size_t t = read<size_t>(); t--;)
    {
        ll n, m;
        cin >> n >> m;
        n = 0;
        vector<ll> a(m);
        for(ll i = 0; i < m; ++i)
        {
            cin >> a[i];
            n += a[i];
        }
        ll ans = 1;
        for (ll i = 0; i < m; ++i)
        {
            ans *= comb.c(n, a[i]).v;
            n -= a[i];
            ans %= MOD;
        }
        cout << ans << '\n';
    }
}
}

