        }
        for(ll i = 0; i < 16; ++i)
        {
            if(i - 4 >= 0)
            {

                ll t = swap(x, i, i - 4);
                if(a[t] == 0)
                {
                    q.push({t, step + 1});
                    a[t] = 1;
                }
            }
            if(i + 4 < 16)
            {
                ll t = swap(x, i, i + 4);
                if(a[t] == 0)
                {
                    q.push({t, step + 1});
                    a[t] = 1;
                }
            }
            if((i + 1) % 4 != 0 and i + 1 < 16)
            {
                ll t = swap(x, i, i + 1);
                if(a[t] == 0)
                {
                    q.push({t, step + 1});
                    a[t] = 1;
                }
            }
            if((i - 1) >= 0 and (i - 1) % 4 != 3)
            {
                ll t = swap(x, i, i - 1);
                if(a[t] == 0)
                {
                    q.push({t, step + 1});
                    a[t] = 1;
                }
            }
        }
    }
}
