inline int64_t Pow(int64_t a, int64_t b) {
	int64_t ans = 1, base = a;
	while (b)
	{
		if (b & 1)
		{
			ans *= base;
			ans %= N;
		}
		base *= base;
		base %= N;
		b >>= 1;
	}
	return ans;

