#include <iostream>
void Sort(int* start, int size) {
	for(int i=size-1; i>=0; --i) {
		int max_value = 0;
		int max_index = 0;
		for(int j=0; j <= i; ++j) {
			if(start[j] > start[max_index]) {
				max_index = j;
				max_value = start[j];
			}
		}
		std::swap(start[i], start[max_index]);
	}
}
