    int n = 0;
    std::cin >> n;

    int i = 1;
    int j = (n + 1) / 2;
    m[i][j] = 1;
    for (int k = 2; k <= n*n; ++k) {
        if (i == 1 and j != n) {
            m[i=n][++j] = k;
        }
        else if (j == n and i != 1) {
            m[--i][j=1] = k;
        }
        else if (i == 1 and j == n) {
            m[++i][j] = k;
        }
        else {
            if (m[i-1][j+1] == 0) {
                m[--i][++j] = k;
            }
            else {
                m[++i][j] = k;
            }
        }
    }

    for (int i = 1; i <= n; ++i) {
        for (int j = 1; j <= n; ++j) {
            std::cout << m[i][j] << ' ';
        }
        std::cout << '\n';
    }
    return 0;
}

