using namespace std;

vector<uint64_t> prime(uint64_t n)
{
	vector<uint64_t> ans(1,0);
	if(n >= 2)
	{
		ans.push_back(2);
	}
	if(n >= 3)
	{
		ans.push_back(3);
	}
	for(uint64_t i = 4;i <= n;++i)
	{
		bool is_prime = true;
		for(uint64_t j = 2;j*j <= i;++j)
		{

			if(i%j == 0)
			{
				is_prime = false;
				break;
			}
		}
		if(is_prime == true)
		{
			ans.push_back(i);
		}
	}
	return ans;
}
int main()
{
    int n;
    while(cin >> n)
    {
		vector<uint64_t> prime_n = prime(n);
		vector<vector<uint64_t>> dp(prime_n.size(),vector<uint64_t>(n+1));
		dp[0][0] = 1;
		for(uint64_t i = 1; i < prime_n.size(); ++i)
		{
			dp[i][0] = 1;
			for(uint64_t j = 0; j <= n;++j)
			{
				uint64_t a = dp[i-1][j];
				uint64_t b = 0;
				if(j >= prime_n[i])
				{
					b = dp[i][j-prime_n[i]];
				}
//			cout << a << b << endl;
				dp[i][j] = a+b;
			}
		}
		cout << dp.back()[n] << endl;
    } 
}

