int main(){
    cin>>n>>c;
    for(register int i=1;i<=n;++i){
        cin>>a[i].w>>a[i].v;
        a[i].p=a[i].v/a[i].w;//性价比=价格/重量 
    }
    sort(a+1,a+n+1,cmp);//将性价比排序 
    for(register int i=1;i<=n;++i){
        if(c>=a[i].w){//金币的重量小于或等于背包的承重量
            c-=a[i].w;//装上该堆金币后背包的剩余承重量 
            sum+=a[i].v;//金币的价值 
        }
