{
    char op = ops.top();
    ops.pop();
    ll js1 = jss.top();
    jss.pop();
    ll js2 = jss.top();
    jss.pop();
    if (op == '*')
    {
        jss.push(js1 * js2 % 10000);
    }
    if (op == '+')
    {
        jss.push(js1 + js2 % 10000);
    }
}
