    while (cin >> op)
    {
        while (not ops.empty() and (ops.top() == '*' or (ops.top() == '+' and op == '+')))
        {
            js(jss, ops);
        }
        cin >> s;
        ops.push(op);
        jss.push(s);
    }
    while (not ops.empty())
    {
        js(jss, ops);
    }
