namespace submit1
{
vector<ll> prime(ll n)
{
    vector<ll> ans(1,0);
    if(n >= 2)
    {
        ans.push_back(2);
    }
    if(n >= 3)
    {
        ans.push_back(3);
    }
    for(ll i = 4;i <= n;++i)
    {
        bool is_prime = true;
        for(ll j = 2;j*j <= i;++j)
        {

            if(i%j == 0)
            {
                is_prime = false;
                break;
            }
        }
        if(is_prime == true)
        {
            ans.push_back(i);
        }
    }
    return ans;
}
void Main()
{
    ll n = Read<int>();
    vector<ll> prime_n = prime(n);
    vector<vector<ll>> dp(prime_n.size() + 1, vector<ll>(n + 1));
    for (size_t i = 1; i < dp.size(); ++i)
    {
        dp[i][0] = 1;
        ASSERT(i < dp.size());
        for (size_t j = 1; j < dp[0].size(); ++j)
        {
            ll a = 0;
            if (j >= prime_n[i])
            {
                a = dp[i][j - prime_n[i]];
            }
            dp[i][j] = dp[i - 1][j] + a;
        }
    }
    cout << dp.back().back();
}
}

