#include <iostream>
#include <vector>

using namespace std;

int main()
{
	int64_t n,x;
	cin >> n >> x;
	vector<int64_t> lose(n+1);
	vector<int64_t> win(n+1);
	vector<int64_t> use(n+1);
	for(int64_t i = 1;i <= n;++i)
	{
		cin >> lose[i] >> win[i] >> use[i];
	}
	vector<vector<int64_t>> dp(n+1,vector<int64_t>(x+1));
	for(int64_t i=1;i <= n;++i)
	{
		for(int64_t j = 0;j <= x;++j)
		{
			int64_t a = dp[i-1][j] + lose[i]; 
			int64_t b = 0;
			if(use[i] <= j)
			{
				b = win[i]+dp[i-1][j-use[i]];
			}
			dp[i][j] = max(a,b);
 		}
	}
	cout << dp[n][x]*5;
}

