struct Corr
{
    int x, y, step;
};
void Main()
{
    auto const n = Read<int>();
    auto zs = vector<vector<char>>(n + 2, vector<char>(n + 2, '1'));
    for (int i = 1; i <= n; ++i)
    {
        for (int j = 1; j <= n; ++j)
        {
            cin >> zs[i][j];
        }
    }
    int x1, y1, x2, y2;
    cin >> x1 >> y1 >> x2 >> y2;
    queue<Corr> q;
    q.push({x1, y1, 1});
    const int move[4][2] = 
        {
            {
                0, 1
            },
            {
                0, -1
            },
            {
                1, 0
            },
            {
                -1, 0
            }
        };

    while (not q.empty())
    {
        auto const now = q.front();
        q.pop();
        for (auto i : move)
        {
            int new_x = now.x + i[0];
            int new_y = now.y + i[1];
            if (new_x == x2 and new_y == y2)
            {
                cout << now.step << endl;
                return;
            }
            if (zs[new_x][new_y] != '1')
            {
                q.push(Corr{new_x, new_y, now.step + 1});
                zs[new_x][new_y] = '1';
            }
        }

    }
}
}

