using namespace std;

int main()
{
	int n, m;
	cin >> n >> m;

	set<int> xx;
	vector<int> xs(m);

	for (int i=0; i<n; ++i)
	{
		int t;
		cin >> t;
		xx.insert(t);
	}

	for (int i=0; i < m; ++i)
	{
		cin >> xs[i];
	}

	sort(begin(xs), end(xs));
	uint64_t ans=0;
	auto it = begin(xx);
	for(auto m: xs)
	{
		it = lower_bound(it, end(xx), m);

		auto right = INT_MAX;
		if (it != end(xx)) {
			right = (*it) - m;
			if (right == 0) {
				break;
			}
		}

		auto left = INT_MAX;
		if (it != begin(xx)) {
			left = m - *(--it);
 		}

		ans += min(left, right);
	}
	cout << ans;
	return 0;
}

