const int MAX_LEN = 1000000;

int faces[MAX_LEN];
char names[MAX_LEN][20];

int main() {
	int n;
	int m;
	cin >> n >> m;

	for(int i=0; i<n; ++i) {
		cin >> faces[i] >> names[i];
		if(faces[i] == 0) {
			faces[i]=-1;
		}
	}

	int index=0;
	while (m--) {
		int d, s;
		cin >> d >> s;
		if (d == 0){
			d = -1;
		}
		index -= d * faces[index] * s;
		index %= n;
		if (index < 0) {
			index += n;
		}
	}
	cout << names[index];
	return 0;
}

