long long int Sort2(int* start, int size) {
	int ret=0;
	for(int i=size-1; i>=0; --i) {
		for(int j=0; j < i; ++j) {
			if(start[j] > start[j+1]) {
				std::swap(start[j], start[j+1]);
				if(start[j]!=start[j+1]){
					ret++;
				}
			}
		}
	}
	return ret;
}
