int prime(int n)
{
    int t = n;
    int ans = 0;
    for (int i = 2; i * i <= t; ++i)
    {
        if(n % i == 0)
        {
            ++ans;
            while (n % i == 0)
            {
                n /= i;
            }

        }
    }
    if (n > 1)
    {
        ++ans;
    }
    return ans;
}

