int64_t dp[32] = {1,1};

int ktl(int n){
  if(dp[n]!=0)
    {
      return dp[n]; 
    }
  int ret=0;
  for(int i=0;i<n;i++){
    ret+=ktl(i)*ktl(n-i-1);
  }
  dp[n] = ret;
  return ret;
}
