using namespace std;

string Reverse(string a)
{
    reverse(begin(a),end(a));
    return a;


}
bool Huiwen(string a)
{
    return a==Reverse(a);

}
char C2i(char a)
{
    if(a>='0' and a<='9')
    {
	return a-'0';

    }
    return tolower(a)-'a'+10;

}
char I2c(int a)
{
    if(a<10)
    {
	return a+'0';

    }
    return a-10+'A';

}
string Add(int n,string a,string b)
{
    a=Reverse(a);
    b=Reverse(b);


    string r;
    int jw = 0;

    size_t i = 0;

    while(not (i>=a.size() and i>=b.size() and jw == 0))
    {
	int ai = (i>=a.size())?0:C2i(a[i]);
	int bi = (i>=b.size())?0:C2i(b[i]);


	int t = jw+ai+bi;
	jw = t/n;
	t%=n;
	r+=I2c(t);
	++i;

    }
    return Reverse(r);
}
