  - dp[i] = 以下标i结束的最长公共子序列
*/

int main()
{
   int n;
   cin >> n;
   vector<int>a(n);

   for(int i = 0; i < n; ++i)
   {
      cin >> a[i];
   }
   vector<int>dp(n,1);
   int ans = 0;
   for(int i = 1;i < n; ++i)
   {
      for(int j = 0; j < i; ++j)
      {
	 if(a[j] < a[i])
	 {
	    dp[i] = max(dp[i], dp[j]+1);
	 }
      }
      ans = max(ans,dp[i]);
   }
   cout << ans; 
}

