DB delta[]={0, 0.235, 0.3746, 0.1246, 0.2153, 0.364, 0.1253, 0.6124, 0.164, 0.7543, 0.35476};
int n, cnt, T; 
DB a[520][520], b[520][520], c[520][520], e[520], ans[2100][50][50], r[5020]; 
il void Chu_ans(DB d) { 
    for(int i = 1; i <= n; ++i) e[i] = c[i][n+1] * d + c[i][n + 2]; ++cnt; 
    for(int i = 1; i <= n; ++i) { DB s = 0; for_1(j, n) s += a[i][j] * e[j]; s -= d; for_1(j, n) ans[cnt][i][j] = a[i][j] - s * e[j];  }
}
il void Guass() {
    memcpy(c, b, sizeof(b));
    for_1(i, n) {
        int id = i; for(int j = i; j <= n; ++j) if(fabs(c[j][i]) > fabs(c[id][i])) id = j;  swap(c[id], c[i]); 
        for(int j = 1; j <= n; ++j) { 
            if(i != j) { 
                DB t = c[j][i] / c[i][i]; 
                for(int k = 1; k <= n + 2; ++k) c[j][k] -= c[i][k] * t;
            }
        }
        DB tmp = 1.0 / c[i][i]; for(int j = 1 ; j <= n + 2 ; j++) c[i][j] *= tmp;
    }
    DB A = 0, B = 0, C = 0;//二元一次方程
    for(int i = 1; i <= n; ++i) { A += c[i][n + 1] * c[i][n + 1]; B += 2 * c[i][n + 1] * c[i][n + 2]; C += c[i][n + 2] * c[i][n + 2]; }
    C--; //A+C+B=1,故让r2--
    if(fabs(A) < eps) { Chu_ans(-C/B); }
    else {//直接算公式
        DB d = B * B - 4 * A * C; d = max(d, (DB)0); 
        if(d < eps) {Chu_ans(-B / (2 * A));}
        else {  Chu_ans((-B + sqrt(d)) / (2 * A)); Chu_ans((-B - sqrt(d)) / (2 * A));  }
    }
}

void dfs(int x) { 
    if(x == n + 1) {Guass(); return ; }
    for(int i = 1 ; i <= n ; i++) b[x][i] = a[x][i]; b[x][n + 1] = 1; b[x][n + 2] = r[x];
    dfs(x + 1); if(fabs(r[x]) < eps) return; b[x][n + 2] = -r[x]; dfs(x + 1); 
}

