#include <iostream>
#include <vector>
#include <algorithm>

struct Cell {
    int row, col, score;
    std::vector<int> candidates;
};

class TargetSudoku {
public:
    int sudoku[9][9];
    int scores[9][9];
    int rows[9], cols[9], boxes[9];
    std::vector<Cell> empty_cells;
    int max_score;

    TargetSudoku() {
        max_score = -1;
        for (int i = 0; i < 9; ++i) {
            rows[i] = cols[i] = boxes[i] = 0;
        }
    }

    void readInput() {
        for (int row = 0; row < 9; ++row) {
            for (int col = 0; col < 9; ++col) {
                std::cin >> sudoku[row][col];
                int distance = std::max(std::abs(row - 4), std::abs(col - 4));
                scores[row][col] = 10 - distance;
                if (sudoku[row][col] != 0) {
                    int num = sudoku[row][col] - 1;
                    rows[row] |= (1 << num);
                    cols[col] |= (1 << num);
                    int box = (row / 3) * 3 + (col / 3);
                    boxes[box] |= (1 << num);
                } else {
                    empty_cells.push_back({row, col, scores[row][col]});
                }
            }
        }
    }

    void computeCandidates() {
        for (auto& cell : empty_cells) {
            int row = cell.row;
            int col = cell.col;
            int box = (row / 3) * 3 + (col / 3);
            int used = rows[row] | cols[col] | boxes[box];
            int candidates_mask = ~used & 0x1FF;
            cell.candidates.clear();
            for (int num = 8; num >= 0; --num) {
                if (candidates_mask & (1 << num)) {
                    cell.candidates.push_back(num + 1);
                }
            }
        }
    }

    void sortCells() {
        std::sort(empty_cells.begin(), empty_cells.end(),
                  [](const Cell& a, const Cell& b) {
                      if (a.score != b.score) {
                          return a.score > b.score;
                      } else {
                          return a.candidates.size() < b.candidates.size();
                      }
                  });
    }

    void backtrack(int index, int current_score) {
        if (index == empty_cells.size()) {
            if (current_score > max_score) {
                max_score = current_score;
            }
            return;
        }

        const Cell& cell = empty_cells[index];
        int row = cell.row;
        int col = cell.col;
        int score = cell.score;
        int box = (row / 3) * 3 + (col / 3);

        for (int num : cell.candidates) {
            int num_mask = 1 << (num - 1);
            if (!(rows[row] & num_mask) && !(cols[col] & num_mask) && !(boxes[box] & num_mask)) {
                sudoku[row][col] = num;
                rows[row] |= num_mask;
                cols[col] |= num_mask;
                boxes[box] |= num_mask;
                current_score += score * num;
                backtrack(index + 1, current_score);
                current_score -= score * num;
                sudoku[row][col] = 0;
                rows[row] &= ~num_mask;
                cols[col] &= ~num_mask;
                boxes[box] &= ~num_mask;
            }
        }

        int remaining_sum = 0;
        for (int i = index + 1; i < empty_cells.size(); ++i) {
            int max_num = *max_element(empty_cells[i].candidates.begin(), empty_cells[i].candidates.end());
            remaining_sum += empty_cells[i].score * max_num;
        }
        if (current_score + remaining_sum <= max_score) {
            return;
        }
    }

    void solve() {
        readInput();
        computeCandidates();
        sortCells();
        backtrack(0, 0);
        std::cout << max_score << std::endl;
    }
};

int main() {
    TargetSudoku solver;
    solver.solve();
    return 0;
}

