int gcd(int a, int b) {
    if (a == 0) return b;
    if (b == 0) return a;
    return gcd(a % b, b % a);
}

int main() {
    while(1) {
        ans = 0;
        cin >> n;
        if (n == 0) return 0;
        for (int i = 2; (long long)(i * i) <= abs(n); i++) {
            k = 0;
            while(n % i == 0) {
                n /= i;
                k++;
            }
            ans = gcd(ans, k);
        }
        if (abs(n) != 1) cout << 1;
        else {
            if (n == -1) {
                if (ans != 0) while (ans % 2 == 0) ans /= 2;
            }
            cout << ans;
        }
        cout << endl;
    }
}

