int64_t dfs(vector<vector<int>>& a, int x, int y, int f)
{
    if(x >= n or y >= m or x < 0 or y < 0)
    {
	return INT64_MIN;
    }

    if(x == n-1 and y == m-1)
    {
	Debug("found!");
	return a.back().back();
    }

    int64_t ans = INT64_MIN;

    if (Right == f)
    {
	ans = max({
		dfs(a,x+1,y, Right), 
		dfs(a,x,y+1, Down), 
		dfs(a,x,y-1, Up)});
    }
    else if(Up == f)
    {
	ans = max(ans,dfs(a,x+1,y,Right));
	ans = max(ans,dfs(a,x,y-1,Up));
    }
    else if(Down == f)
    {
	ans = max(ans,dfs(a,x+1,y, Right));
	ans = max(ans,dfs(a,x,y+1, Down));
    }
    else
    {
	assert(false);
    }
    if (ans == INT64_MIN) {
	return ans;
    }
    return ans+a[x][y];
}


