int use[maxn];
priority_queue<node2>q;
vector<node>p[maxn];
void dijkstra(int sx){
	for(int i=0;i<=maxn;i++)dis[i]=0;
	q.push((node2){sx,1});
	dis[sx]=1;
	while(!q.empty()){
		node2 now=q.top();q.pop();
