		if(use[u])continue;
		use[u]=1;
		for(int i=0;i<p[u].size();i++){
			int v=p[u][i].to;
			if(dis[v]<dis[u]*p[u][i].w){
				dis[v]=dis[u]*p[u][i].w;
				q.push((node2){v,dis[v]});
			}
		}
	}
}
